#pragma once
#define BATTERIES_COMPRESSED_TUPLE_HPP

#include <batteries/config.hpp>
//

#include <batteries/int_types.hpp>
#include <batteries/type_traits.hpp>
#include <batteries/utility.hpp>

namespace batt {

// Forward-declaration of CompressedTuple implementation template.
//
template <usize N, typename... Ts>
class CompressedTupleImpl;

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename... Ts>
using CompressedTuple = CompressedTupleImpl<sizeof...(Ts), Ts...>;

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <usize I, typename T>
struct BATT_IF_MSVC(__declspec(empty_bases)) CompressedTupleElement : T {
    using value_type = T;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <usize N, typename First, typename... Rest>
class BATT_IF_MSVC(__declspec(empty_bases)) CompressedTupleImpl<N, First, Rest...>
    : protected CompressedTupleElement<(N - (1 + sizeof...(Rest))), First>
    , public CompressedTupleImpl<N, Rest...>
{
   public:
    using Self = CompressedTupleImpl<N, First, Rest...>;

    static constexpr usize kIndex = (N - (1 + sizeof...(Rest)));

    using Element = CompressedTupleElement<kIndex, First>;

    using Super = CompressedTupleImpl<N, Rest...>;

    template <usize I>
    using FindElement = std::conditional_t<(I == kIndex), Element, typename Super::template FindElement<I>>;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    template <usize I, typename T>
    static Self& from_element(T& value) noexcept
    {
        return *static_cast<Self*>(                      //
            static_cast<CompressedTupleElement<I, T>*>(  //
                std::addressof(value)));
    }

    template <usize I, typename T>
    static const Self& from_element(const T& value) noexcept
    {
        return *static_cast<const Self*>(                      //
            static_cast<const CompressedTupleElement<I, T>*>(  //
                std::addressof(value)));
    }

    static constexpr usize size() noexcept
    {
        return N;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    CompressedTupleImpl() = default;

    CompressedTupleImpl(const Self&) = default;

    CompressedTupleImpl(Self&&) = default;

    Self& operator=(const Self&) = default;

    Self& operator=(Self&&) = default;

    ~CompressedTupleImpl() = default;

    template <typename FirstArg, typename... RestOfArgs,
              typename = EnableIfNoShadow<Self, FirstArg, RestOfArgs...>>
    BATT_REQUIRES((sizeof...(RestOfArgs) == sizeof...(Rest)) && (!std::same_as<std::decay_t<FirstArg>, Self>))
    CompressedTupleImpl(FirstArg&& first, RestOfArgs&&... rest)
        : Element{BATT_FORWARD(first)}
        , Super{BATT_FORWARD(rest)...}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    template <isize I>
    BATT_REQUIRES(I >= 0 && I < N)
    BATT_ALWAYS_INLINE auto& get() & noexcept
    {
        return *static_cast<FindElement<I>*>(this);
    }

    template <isize I>
    BATT_REQUIRES(I >= 0 && I < N)
    BATT_ALWAYS_INLINE const auto& get() const& noexcept
    {
        return *static_cast<const FindElement<I>*>(this);
    }

    template <isize I>
    BATT_REQUIRES(I >= 0 && I < N)
    BATT_ALWAYS_INLINE auto&& get() && noexcept
    {
        return std::move(*static_cast<FindElement<I>*>(this));
    }

    template <isize I>
    BATT_REQUIRES(I >= 0 && I < N)
    BATT_ALWAYS_INLINE const auto&& get() const&& noexcept
    {
        return std::move(*static_cast<const FindElement<I>*>(this));
    }
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize N>
class CompressedTupleImpl<N>
{
   public:
    template <usize I>
    using FindElement = void;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
struct tuple_size;

template <typename... Ts>
struct tuple_size<CompressedTuple<Ts...>> : std::integral_constant<usize, CompressedTuple<Ts...>::size()> {
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <usize I, typename T>
struct tuple_element;

template <usize I, typename... Ts>
struct tuple_element<I, CompressedTuple<Ts...>> : std::tuple_element<I, std::tuple<Ts...>> {
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize I, typename T>
using tuple_element_t = typename tuple_element<I, T>::type;

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize I, typename T>
decltype(auto) get(T&& t) noexcept
{
    return BATT_FORWARD(t).template get<I>();
}

}  // namespace batt
